from functools import lru_cache

def brute(a):
    n=len(a)
    pre=[0]
    for x in a: pre.append(pre[-1]+x)
    def s(l,r): return pre[r]-pre[l-1]
    ans=0
    for k in range(1,n+1):
      ok=False
      def dfs(idx,prev_sum,start):
        nonlocal ok
        if idx>k:
          ok=True; return
        ln=k-idx+1
        for l in range(start,n-ln+2):
          r=l+ln-1
          sm=s(l,r)
          if sm>prev_sum:
            dfs(idx+1,sm,r+1)
            if ok:return
      dfs(1,-1,1)
      if ok: ans=k
    return ans

for a in ([1,2,3],[1,1,2,2,3],[1,2,1,1,3,2,6],[9,6,7,9,7]):
    print(a, brute(a))
