import sys

def solve_case(a):
    n = len(a)
    a = [0] + a
    pref = [0] * (n + 1)
    for i in range(1, n + 1):
        pref[i] = pref[i - 1] + a[i]

    NEG = -10**30
    dp_prev = [NEG] * (n + 1)
    for i in range(1, n + 1):
        dp_prev[i] = pref[i] - pref[i - 1]
    ans = 1
    length = 2
    while length * (length + 1) // 2 <= n:
        dp_cur = [NEG] * (n + 1)
        best = NEG
        for r in range(length, n + 1):
            j = r - length
            if dp_prev[j] != NEG:
                cand = dp_prev[j] - pref[j]
                if cand > best:
                    best = cand
            cur_sum = pref[r] - pref[r - length]
            if best < cur_sum:
                dp_cur[r] = cur_sum
        if max(dp_cur) == NEG:
            break
        dp_prev = dp_cur
        ans = length
        length += 1
    return ans


def brute(a):
    n = len(a)
    pref = [0]
    for x in a:
        pref.append(pref[-1] + x)
    def seg(l,r):
        return pref[r]-pref[l-1]
    best = 0
    for k in range(1, n+1):
        ok = False
        def dfs(idx, start, prev):
            nonlocal ok
            if ok:
                return
            if idx == k+1:
                ok = True
                return
            ln = k-idx+1
            for l in range(start, n-ln+2):
                r = l+ln-1
                s = seg(l,r)
                if s > prev:
                    dfs(idx+1, r+1, s)
        dfs(1,1,-1)
        if ok:
            best = k
    return best

from random import randint, seed
seed(0)
for n in range(1, 11):
    for _ in range(200):
        a = [randint(1, 9) for _ in range(n)]
        s = solve_case(a)
        b = brute(a)
        if s != b:
            print('mismatch', n, a, s, b)
            sys.exit()
print('ok')
