def solve_case(a):
    n = len(a)
    a = [0] + a
    pref = [0]*(n+1)
    for i in range(1,n+1):
        pref[i]=pref[i-1]+a[i]

    maxk = 0
    while (maxk+1)*(maxk+2)//2 <= n:
        maxk += 1

    INF = 10**30
    prev = [INF]*(n+1)
    for i in range(n+1):
        prev[i] = -INF
    # k=1: choose one segment of length 1 ending at i, store minimal possible last sum
    cur = [INF]*(n+1)
    best = INF
    for i in range(1,n+1):
        best = min(best, pref[i]-pref[i-1])
        cur[i] = best
    ans = 1
    prev = cur

    for k in range(2, maxk+1):
        length = k
        cur = [INF]*(n+1)
