                if prev[j] < s:
                    cur[i] = min(cur[i], s)
            elif j == 0:
                # no room for previous segments since total previous length > 0
                pass
            if cur[i] < INF:
                possible = True
        if not possible:
            break
        prev = cur
        ans = k
    return ans


