def fast(a):
    n=len(a)
    pref=[0]
    for x in a: pref.append(pref[-1]+x)
    INF=10**30
    # f[len][i] = minimum possible last segment sum for a valid chain of lengths 1..len ending exactly at i? 
    # Transition: previous chain len-1 ends at p <= i-len, and sum(p+1..i) > prev_sum.
    dp=[INF]*(n+1)
    ans=0
    for length in range(1,n+1):
        ndp=[INF]*(n+1)
        best=INF
        p=0
        for i in range(1,n+1):
            if length==1:
                ndp[i]=a[i-1]
            else:
                if i>=length:
                    # include p=i-length from previous layer into best
                    cand=dp[i-length]
                    if cand<best:
                        best=cand
                    s=pref[i]-pref[i-length]
                    if best<s:
                        ndp[i]=s
        ok=False
        for i in range(1,n+1):
            if ndp[i]<INF:
                ok=True;break
        if ok:
            ans=length
            dp=ndp
        else:
            break
    return ans

